export function rollForTheme(themeId: ThemeId): RollResult {
  const totalWeight = RARITIES.reduce((sum, r) => sum + r.weight, 0);
  let roll = Math.random() * totalWeight;
  let chosenRarity: Rarity = "common";
  for (const r of RARITIES) {
    if (roll < r.weight) {
      chosenRarity = r.id;
      break;
    }
    roll -= r.weight;
  }

  const pool = RESULT_POOLS[themeId].filter((r) => r.rarity === chosenRarity);
  const seed = pool[Math.floor(Math.random() * pool.length)];

  return {
    resultId: `${themeId}-${seed.title}-${Date.now()}-${Math.floor(Math.random() * 10000)}`,
    rollId: null,
    title: seed.title,
    emoji: seed.emoji,
    flavor: seed.flavor,
    rarity: seed.rarity,
    themeId,
  };
}

export function findFlavorByTitle(themeId: ThemeId, title: string): string {
  const seed = RESULT_POOLS[themeId].find((s) => s.title === title);
  return seed?.flavor ?? "";
}
